// src/App.js
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { incoming: null, onDelete: () => {} }, // will be injected/kept up-to-date
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ]);

  // Delete the target node and also remove the DeleteNode itself (id: "5")
  const handleDeleteNode = (targetId) => {
    // remove the target node and the delete node
    setNodes((nds) => nds.filter((n) => n.id !== targetId && n.id !== "5"));

    // remove any edges connected to the target or the delete node
    setEdges((eds) =>
      eds.filter(
        (e) =>
          e.source !== targetId &&
          e.target !== targetId &&
          e.source !== "5" &&
          e.target !== "5"
      )
    );
  };

  // Handle new connections (onConnect). If connected to delete node (target === "5"),
  // update deleteNode.incoming immediately and add the edge.
  const handleConnect = (params) => {
    // create a stable id for the new edge if not provided
    const newEdge = {
      id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
      source: params.source,
      target: params.target,
      ...params,
    };

    setEdges((eds) => {
      const next = [...eds, newEdge];

      // if the new edge points to delete node, update its incoming
      if (newEdge.target === "5") {
        setNodes((nds) =>
          nds.map((n) =>
            n.id === "5"
              ? {
                  ...n,
                  data: { ...n.data, incoming: newEdge.source, onDelete: handleDeleteNode },
                }
              : n
          )
        );
      }

      return next;
    });
  };

  // Handle edge changes (add/remove/select). We call onEdgesChange to let reactflow update its internal state,
  // then inspect the `changes` array to update deleteNode.incoming accordingly.
  const handleEdgesChange = (changes) => {
    // Let reactflow apply the changes to its internal state
    onEdgesChange(changes);

    // Derive incoming for delete node from the changes (avoid reading stale edges)
    // If an edge was added with target "5", set incoming to its source.
    // If an edge was removed with target "5", clear incoming.
    // If multiple changes occur, the last relevant change wins.
    setNodes((nds) => {
      // find current incoming (fallback to existing)
      let incoming = nds.find((n) => n.id === "5")?.data?.incoming ?? null;

      for (const change of changes || []) {
        // reactflow change object shape: { type: 'add'|'remove'|'reset'|'update', item: edge }
        const item = change.item;
        if (!item) continue;

        if ((change.type === "add" || change.type === "update") && item.target === "5") {
          incoming = item.source;
        }

        if (change.type === "remove" && item.target === "5") {
          // if the removed edge targeted delete node, clear incoming
          incoming = null;
        }
      }

      return nds.map((n) =>
        n.id === "5"
          ? { ...n, data: { ...n.data, incoming, onDelete: handleDeleteNode } }
          : n
      );
    });

    // We don't call setEdges here because onEdgesChange already updated the edges state.
  };

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={handleEdgesChange}
        onConnect={handleConnect}
      />
    </div>
  );
}

export default App;
